external_knowledge:
- 'young female explorers' refers to female respondents;
- 'in the eyes of' means the perspectives of the respondents;
- 'shining brightly in the cosmic year of 2020' refers to films watched between January 1, 2020, and December 31, 2020;
- 'awarded them with a place among the top celestial bodies' means ranking the films within the top 3.

sql:
SELECT COUNT(DISTINCT respondent_id) 
FROM responses 
WHERE have_seen_films = 'Yes';

SELECT characters.character_name, character_perceptions.favorability, character_perceptions.perception_reason
FROM character_perceptions
JOIN characters ON character_perceptions.character_name = characters.character_name;

SELECT AVG(rank) 
FROM film_rankings 
WHERE response_id IN (
  SELECT response_id 
  FROM responses
);

SELECT fan_status, COUNT(*) AS fan_status_count
FROM expanded_universe
GROUP BY fan_status;

SELECT DISTINCT respondents.respondent_id, respondents.age_group, respondents.gender, respondents.location
FROM respondents
JOIN film_views ON respondents.respondent_id = film_views.response_id;

SELECT COUNT(fandom_id) AS total_star_trek_fans
FROM star_trek_fandom
WHERE fandom_status = 'Yes';

SELECT 
    (SELECT COUNT(*) FROM responses WHERE have_seen_films = 'Yes' AND fan_status = 'Star Wars fan') * 1.0 /
    (SELECT COUNT(*) FROM responses WHERE have_seen_films = 'No' AND fan_status = 'Star Wars fan') AS ratio;
